/* globe.js — peer globe for the BCHN dashboard.
 * WebGL renderer ported from LoneStrike BTC ui/src/globe-webgl.js (rev42),
 * Cash palette. Coastlines: world-atlas land-50m, baked in at build time.
 * Peer countries come from /api/status, resolved on the node from the DB-IP
 * table (CC BY 4.0, https://db-ip.com). No runtime network calls.
 */
// ============================================================================
// Coastline rings — world-atlas land-50m, quantised to 0.1°, delta+varint,
// base64. 1,363 rings / 49,140 points in ~100 KB. Ships with the image; the
// dashboard never fetches it at runtime.
// ============================================================================
const RINGS_B64 = "";
function decodeRings(b64) {
  const b = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
  let p = 0;
  const vi = () => { let n = 0, s = 0, c; do { c = b[p++]; n |= (c & 127) << s; s += 7; } while (c & 128); return n >>> 0; };
  const zz = () => { const n = vi(); return (n >>> 1) ^ -(n & 1); };
  const nRings = vi(), rings = [];
  for (let i = 0; i < nRings; i++) {
    const n = vi(), r = new Array(n);
    let x = 0, y = 0;
    for (let j = 0; j < n; j++) { x += zz(); y += zz(); r[j] = [x / 10, y / 10]; }
    rings.push(r);
  }
  return rings;
}
const RINGS = decodeRings(RINGS_B64);

// ============================================================================
// Cash palette for the globe. BTC ships amber land on near-black ocean; this
// is the same structure with LoneStrike green.
// ============================================================================
const PAL = {
  ocean:     'rgb(7, 18, 14)',
  land:      'rgb(10, 193, 142)',
  coastline: 'rgb(4, 62, 46)',
  cities:    'rgb(226, 255, 243)',
  frostRgb:  [198, 240, 222],
};

// ---- FBM noise (verbatim from globe-webgl.js) ------------------------------
function _hash2(x, y) {
  let h = x * 374761393 + y * 668265263;
  h = (h ^ (h >> 13)) * 1274126177;
  return ((h ^ (h >> 16)) >>> 0) / 4294967295;
}
function _valueNoise(x, y) {
  const ix = Math.floor(x), iy = Math.floor(y);
  const fx = x - ix, fy = y - iy;
  const a = _hash2(ix, iy), b = _hash2(ix + 1, iy), c = _hash2(ix, iy + 1), d = _hash2(ix + 1, iy + 1);
  const sx = fx * fx * (3 - 2 * fx), sy = fy * fy * (3 - 2 * fy);
  return a * (1 - sx) * (1 - sy) + b * sx * (1 - sy) + c * (1 - sx) * sy + d * sx * sy;
}
function _fbm(x, y) {
  let v = 0, amp = 1, freq = 1, total = 0;
  for (let i = 0; i < 4; i++) { v += _valueNoise(x * freq, y * freq) * amp; total += amp; amp *= 0.5; freq *= 2; }
  return v / total;
}

// ============================================================================
// bakeWorldMapTexture — ported. TWO FIXES for a non-amber palette:
//
//   BTC: `if (r < 100) continue;`            // "is this pixel land?"
//   BTC: `if (r > 130 && g > 80 && b < 130)` // "can a city light go here?"
//
// Both read the RED channel because BTC's land is rgb(245,168,50). Cash land
// is rgb(10,193,142) — r=10 — so every land pixel would test as ocean: no
// biome shading, no city lights, a flat green disc. Fixed by baking an
// explicit land mask and testing that instead. Palette-agnostic.
// ============================================================================
function bakeWorldMapTexture(rings, opts = {}) {
  const W = opts.width || 2048, H = opts.height || 1024;

  const c = document.createElement('canvas');
  c.width = W; c.height = H;
  const ctx = c.getContext('2d', { willReadFrequently: true });

  // land mask — the fix
  const mc = document.createElement('canvas');
  mc.width = W; mc.height = H;
  const mctx = mc.getContext('2d', { willReadFrequently: true });
  mctx.fillStyle = '#000'; mctx.fillRect(0, 0, W, H);

  ctx.fillStyle = PAL.ocean; ctx.fillRect(0, 0, W, H);

  let touchesSouth = false, touchesNorth = false;
  for (const ring of rings) for (const pt of ring) {
    if (pt[1] <= -85) touchesSouth = true;
    if (pt[1] >= 85) touchesNorth = true;
  }

  // antimeridian split, else polygons stripe across the map
  const drawRingSplit = (g, ring, fill, stroke, lw) => {
    const subs = []; let cur = [], prevLon = null;
    for (const [lon, lat] of ring) {
      if (prevLon !== null && Math.abs(lon - prevLon) > 180) { if (cur.length > 1) subs.push(cur); cur = []; }
      cur.push([lon, lat]); prevLon = lon;
    }
    if (cur.length > 1) subs.push(cur);
    for (const sub of subs) {
      g.beginPath();
      for (let i = 0; i < sub.length; i++) {
        const x = (sub[i][0] + 180) / 360 * W, y = (90 - sub[i][1]) / 180 * H;
        i === 0 ? g.moveTo(x, y) : g.lineTo(x, y);
      }
      g.closePath();
      if (fill) { g.fillStyle = fill; g.fill(); }
      if (stroke) { g.strokeStyle = stroke; g.lineWidth = lw || 1; g.stroke(); }
    }
  };

  for (const ring of rings) {
    if (ring.length < 3) continue;
    drawRingSplit(ctx, ring, PAL.land, null, 0);
    drawRingSplit(mctx, ring, '#fff', '#fff', 1.5);
  }

  const capPx = Math.floor(H * 0.05);
  if (touchesSouth) { ctx.fillStyle = PAL.land; ctx.fillRect(0, H - capPx, W, capPx); mctx.fillStyle = '#fff'; mctx.fillRect(0, H - capPx, W, capPx); }
  if (touchesNorth) { ctx.fillStyle = PAL.land; ctx.fillRect(0, 0, W, capPx); mctx.fillStyle = '#fff'; mctx.fillRect(0, 0, W, capPx); }

  const mask = mctx.getImageData(0, 0, W, H).data;
  const img = ctx.getImageData(0, 0, W, H), data = img.data;

  for (let y = 0; y < H; y++) {
    for (let x = 0; x < W; x++) {
      const i = (y * W + x) * 4;
      if (mask[i] < 128) continue;                 // ocean — was `r < 100`

      // Biome: BTC adds a flat ±25 to r (and less to g/b), which assumes a
      // red-dominant land colour. Scaling all three keeps the hue on green.
      const n = _fbm(x / 60, y / 60);
      const k = 1 + (n - 0.5) * 0.55;
      let nr = data[i] * k, ng = data[i + 1] * k, nb = data[i + 2] * k;

      const absLat = Math.abs(90 - (y / H) * 180);
      if (absLat > 60) {
        const t = Math.min(1, (absLat - 60) / 25);
        nr = nr * (1 - t) + PAL.frostRgb[0] * t;
        ng = ng * (1 - t) + PAL.frostRgb[1] * t;
        nb = nb * (1 - t) + PAL.frostRgb[2] * t;
      }
      data[i] = Math.min(255, nr); data[i + 1] = Math.min(255, ng); data[i + 2] = Math.min(255, nb);
    }
  }
  ctx.putImageData(img, 0, 0);

  for (const ring of rings) { if (ring.length >= 3) drawRingSplit(ctx, ring, null, PAL.coastline, 1.5); }

  // City lights — placed by the mask, not by `r > 130`.
  ctx.fillStyle = PAL.cities;
  let seed = 12345;
  const rand = () => { seed = (seed * 1103515245 + 12345) & 0x7fffffff; return seed / 0x7fffffff; };
  for (let i = 0; i < 1500; i++) {
    const x = Math.floor(rand() * W), y = Math.floor(rand() * H);
    const absLat = Math.abs(90 - (y / H) * 180);
    if (absLat > 62) continue;                       // no city lights on the ice
    if (mask[(y * W + x) * 4] < 128) continue;
    ctx.fillRect(x, y, rand() < 0.85 ? 1 : 2, rand() < 0.85 ? 1 : 2);
  }
  return c;
}

// ============================================================================
// createGlobeWebGL — shaders verbatim from LoneStrike BTC rev42.
// ============================================================================
const VERT = `
precision mediump float;
attribute vec3 aPosition;
uniform float uRotY, uRotX, uTilt, uAspect, uScale;
varying vec3 vNormal, vObjectPos;
void main(){
  vObjectPos = aPosition;
  float cy=cos(uRotY), sy=sin(uRotY);
  vec3 spun = vec3(aPosition.x*cy + aPosition.z*sy, aPosition.y, -aPosition.x*sy + aPosition.z*cy);
  float ct=cos(uTilt), st=sin(uTilt);
  vec3 tilted = vec3(spun.x*ct - spun.y*st, spun.x*st + spun.y*ct, spun.z);
  float cp=cos(uRotX), sp=sin(uRotX);
  vec3 pitched = vec3(tilted.x, tilted.y*cp - tilted.z*sp, tilted.y*sp + tilted.z*cp);
  vNormal = pitched;
  gl_Position = vec4(vec2(pitched.x*uScale/uAspect, pitched.y*uScale), -pitched.z, 1.0);
}`;
const FRAG = `
precision mediump float;
uniform sampler2D uMap;
varying vec3 vNormal, vObjectPos;
const float PI = 3.14159265359;
void main(){
  float lon = atan(vObjectPos.x, vObjectPos.z);
  float lat = asin(clamp(vObjectPos.y, -1.0, 1.0));
  vec2 uv = vec2(fract(lon/(2.0*PI)+0.5), 1.0-(lat/PI+0.5));
  vec3 texColor = texture2D(uMap, uv).rgb;
  vec3 light = normalize(vec3(-0.4, 0.5, 0.85));
  float NdotL = max(0.0, dot(vNormal, light));
  float lit = 0.30 + 0.70*NdotL;
  float cityLight = step(0.85, texColor.r) * step(0.85, texColor.g);
  vec3 baseColor = texColor*lit;
  baseColor += texColor*cityLight*(1.0-NdotL)*0.6;
  float limb = clamp(vNormal.z*1.3 + 0.10, 0.0, 1.0);
  baseColor *= mix(0.62, 1.0, limb);
  gl_FragColor = vec4(baseColor, 1.0);
}`;

function buildSphereMesh(nLat = 48, nLon = 96) {
  const positions = new Float32Array(nLat * nLon * 3); let p = 0;
  for (let i = 0; i < nLat; i++) {
    const lat = -Math.PI / 2 + (i / (nLat - 1)) * Math.PI;
    const cl = Math.cos(lat), sl = Math.sin(lat);
    for (let j = 0; j < nLon; j++) {
      const lon = (j / nLon) * Math.PI * 2;
      positions[p++] = cl * Math.sin(lon); positions[p++] = sl; positions[p++] = cl * Math.cos(lon);
    }
  }
  const idx = [];
  for (let i = 0; i < nLat - 1; i++) for (let j = 0; j < nLon; j++) {
    const a = i * nLon + j, b = i * nLon + ((j + 1) % nLon), c = (i + 1) * nLon + j, d = (i + 1) * nLon + ((j + 1) % nLon);
    idx.push(a, b, c, b, d, c);
  }
  return { positions, indices: new Uint16Array(idx) };
}
function compile(gl, t, src) {
  const s = gl.createShader(t); gl.shaderSource(s, src); gl.compileShader(s);
  if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) { console.error(gl.getShaderInfoLog(s)); return null; }
  return s;
}
const TILT = 23.5 * Math.PI / 180;   // fixed axial tilt, as in rev42

function createGlobeWebGL(canvas) {
  const gl = canvas.getContext('webgl', { antialias: true, alpha: true });
  if (!gl) return null;
  const prog = gl.createProgram();
  gl.attachShader(prog, compile(gl, gl.VERTEX_SHADER, VERT));
  gl.attachShader(prog, compile(gl, gl.FRAGMENT_SHADER, FRAG));
  gl.linkProgram(prog); gl.useProgram(prog);

  const mesh = buildSphereMesh();
  const vbo = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, vbo); gl.bufferData(gl.ARRAY_BUFFER, mesh.positions, gl.STATIC_DRAW);
  const loc = gl.getAttribLocation(prog, 'aPosition');
  gl.enableVertexAttribArray(loc); gl.vertexAttribPointer(loc, 3, gl.FLOAT, false, 0, 0);
  const ibo = gl.createBuffer();
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, ibo); gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, mesh.indices, gl.STATIC_DRAW);

  const U = n => gl.getUniformLocation(prog, n);
  const u = { rotY: U('uRotY'), rotX: U('uRotX'), tilt: U('uTilt'), aspect: U('uAspect'), scale: U('uScale'), map: U('uMap') };
  const tex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, tex);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  gl.uniform1i(u.map, 0);
  gl.uniform1f(u.tilt, TILT);
  gl.enable(gl.DEPTH_TEST); gl.depthFunc(gl.LESS);
  gl.enable(gl.CULL_FACE); gl.cullFace(gl.BACK);
  gl.clearColor(0, 0, 0, 0);

  return {
    setTexture(src) {
      gl.bindTexture(gl.TEXTURE_2D, tex);
      gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, false);
      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, src);
    },
    update({ rotY, rotX, dpr, width, height }) {
      const W = Math.round(width * dpr), H = Math.round(height * dpr);
      if (canvas.width !== W) canvas.width = W;
      if (canvas.height !== H) canvas.height = H;
      gl.viewport(0, 0, W, H);
      gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
      // disk radius = min(W,H) * 0.46  ->  uScale = 0.92 * min(W,H)/H
      gl.uniform1f(u.scale, 0.92 * Math.min(W, H) / H);
      gl.uniform1f(u.rotY, rotY); gl.uniform1f(u.rotX, rotX); gl.uniform1f(u.aspect, W / H);
      gl.drawElements(gl.TRIANGLES, mesh.indices.length, gl.UNSIGNED_SHORT, 0);
    },
  };
}


// ============================================================================
// Peer data — driven by /api/status. country/lat/lon are resolved SERVER-SIDE
// from the DB-IP table baked into the image (dashboard/geo). The browser never
// receives an address it did not already have, and never performs a lookup.
//
//   .onion  -> lat/lon null, by design. Shown on the inner ring, never plotted,
//              never silently dropped.
//   unknown -> lat/lon null. NEVER (0,0): a peer at Null Island is what a
//              silently-failed lookup looks like, and it is indistinguishable
//              from a real result on a globe.
// ============================================================================
const D2R = Math.PI / 180;
let live = [];
let torCount = 0, unplaced = 0, clearCount = 0, total = 0;
let maxAge = 1;

function mk(p) {
  return {
    p,
    la: p.lat != null ? p.lat * D2R : 0,
    lo: p.lon != null ? p.lon * D2R : 0,
    sx: null, sy: null, z: 0, fade: 0, op: 0, alive: true,
    t: Math.random(), spd: 0.10 + 0.16 * (1 - Math.min(260, p.ping || 130) / 260),
  };
}

// Reconcile against the poll rather than rebuilding: a peer that is still here
// keeps its opacity and packet phase, so a refresh doesn't make the whole globe
// blink. Peers that vanished fade out instead of disappearing.
function syncPeers(list) {
  const by = new Map(live.map(o => [o.p.addr, o]));
  const seen = new Set();
  for (const p of list || []) {
    seen.add(p.addr);
    const ex = by.get(p.addr);
    if (ex) {
      ex.p = p; ex.alive = true;
      if (p.lat != null) { ex.la = p.lat * D2R; ex.lo = p.lon * D2R; }
    } else {
      live.push(mk(p));
    }
  }
  for (const o of live) if (!seen.has(o.p.addr)) o.alive = false;
  const ages = live.filter(o => o.alive && o.p.age != null).map(o => o.p.age);
  maxAge = ages.length ? Math.max(...ages) : 1;
  recount();
}

function recount() {
  const on = live.filter(o => o.alive);
  total = on.length;
  torCount = on.filter(o => o.p.tor).length;
  clearCount = on.filter(o => !o.p.tor).length;
  unplaced = on.filter(o => !o.p.tor && o.p.lat == null).length;
  paint();
}
// ============================================================================
// Scene
// ============================================================================
const REDUCED = matchMedia('(prefers-reduced-motion: reduce)').matches;
const ROTX = 0.34;                       // lean the north pole toward the viewer
const glCanvas = document.getElementById('gl');
const ov = document.getElementById('ov');
const octx = ov.getContext('2d');
const field = document.getElementById('field');
const hero = document.getElementById('hero');
const tipEl = document.getElementById('tip');

const globe = createGlobeWebGL(glCanvas);
if (globe) globe.setTexture(bakeWorldMapTexture(RINGS));

let W = 0, H = 0, dpr = 1, R = 0, cx = 0, cy = 0;
function size() {
  const r = field.getBoundingClientRect();
  W = r.width; H = r.height;
  dpr = Math.min(devicePixelRatio || 1, 2);
  ov.width = Math.round(W * dpr); ov.height = Math.round(H * dpr);
  octx.setTransform(dpr, 0, 0, dpr, 0, 0);
  R = 0.46 * Math.min(W, H);           // must match uScale in the shader
  cx = W / 2; cy = H / 2;
}
new ResizeObserver(size).observe(field);
size();

// Mirror the vertex shader exactly, so overlay dots sit on the right pixels.
function project(la, lo, rotY) {
  const cl = Math.cos(la);
  let x = cl * Math.sin(lo), y = Math.sin(la), z = cl * Math.cos(lo);
  const cyr = Math.cos(rotY), syr = Math.sin(rotY);
  let x1 = x * cyr + z * syr, y1 = y, z1 = -x * syr + z * cyr;
  const ct = Math.cos(TILT), st = Math.sin(TILT);
  let x2 = x1 * ct - y1 * st, y2 = x1 * st + y1 * ct, z2 = z1;
  const cp = Math.cos(ROTX), sp = Math.sin(ROTX);
  const x3 = x2, y3 = y2 * cp - z2 * sp, z3 = y2 * sp + z2 * cp;
  return { sx: cx + x3 * R, sy: cy - y3 * R, z: z3 };
}

// Arc: quadratic bezier, control point swung tangentially so every arc sweeps
// the same way. NOTE: with the node anchored at centre-front, the true
// great-circle path projects to a straight line — the curve is a rendering
// convention, not geometry. The anchor stays honest; the sweep is decoration.
function ctrl(sx, sy) {
  const dx = cx - sx, dy = cy - sy;
  const mx = sx + dx * 0.5, my = sy + dy * 0.5;
  const len = Math.hypot(dx, dy) || 1;
  return [mx + (-dy / len) * len * 0.26, my + (dx / len) * len * 0.26];
}
const qpt = (p0, c, p1, t) => {
  const u = 1 - t;
  return [u * u * p0[0] + 2 * u * t * c[0] + t * t * p1[0],
          u * u * p0[1] + 2 * u * t * c[1] + t * t * p1[1]];
};

let rotY = 2.55, last = performance.now(), hover = null;

function frame(now) {
  const dt = Math.min(0.05, (now - last) / 1000); last = now;
  if (!REDUCED) rotY += dt * 0.055;

  if (globe) globe.update({ rotY, rotX: ROTX, dpr, width: W, height: H });
  octx.clearRect(0, 0, W, H);

  // atmosphere
  const g = octx.createRadialGradient(cx, cy, R * 0.94, cx, cy, R * 1.14);
  g.addColorStop(0, 'rgba(10,193,142,.20)');
  g.addColorStop(1, 'rgba(10,193,142,0)');
  octx.fillStyle = g; octx.beginPath(); octx.arc(cx, cy, R * 1.14, 0, 7); octx.fill();

  // join/leave opacity ramp, then retire fully-faded peers
  let retired = false;
  for (const o of live) {
    const target = o.alive ? 1 : 0;
    o.op += (target - o.op) * Math.min(1, dt * 3.2);
    if (!o.alive && o.op < 0.01) retired = true;
    const q = project(o.la, o.lo, rotY);
    o.sx = q.sx; o.sy = q.sy; o.z = q.z;
    o.fade = (q.z <= 0 ? 0 : Math.min(1, q.z / 0.22)) * o.op;
  }
  if (retired) live = live.filter(o => o.alive || o.op >= 0.01);

  const vis = live.filter(o => o.p.lat != null && !o.p.tor && o.fade > 0);

  // arcs — glow pass, then core pass
  octx.lineCap = 'round';
  for (const pass of [0, 1]) {
    for (const o of vis) {
      const c = ctrl(o.sx, o.sy);
      const g2 = octx.createLinearGradient(o.sx, o.sy, cx, cy);
      if (pass === 0) {
        g2.addColorStop(0, 'rgba(10,193,142,' + (0.30 * o.fade).toFixed(3) + ')');
        g2.addColorStop(0.7, 'rgba(10,193,142,' + (0.16 * o.fade).toFixed(3) + ')');
        g2.addColorStop(1, 'rgba(10,193,142,0.05)');
        octx.strokeStyle = g2; octx.lineWidth = 4.5;
      } else {
        g2.addColorStop(0, 'rgba(150,255,214,' + (0.95 * o.fade).toFixed(3) + ')');
        g2.addColorStop(0.55, 'rgba(57,232,180,' + (0.62 * o.fade).toFixed(3) + ')');
        g2.addColorStop(1, 'rgba(10,193,142,' + (0.22 * o.fade).toFixed(3) + ')');
        octx.strokeStyle = g2; octx.lineWidth = 1.5;
      }
      octx.beginPath(); octx.moveTo(o.sx, o.sy); octx.quadraticCurveTo(c[0], c[1], cx, cy); octx.stroke();
    }
  }
  octx.lineCap = 'butt';

  // packets — direction follows getpeerinfo's `inbound`. An inbound peer dialed
  // us, so its traffic runs peer -> node; an outbound peer we dialed, so it runs
  // node -> peer. Same arc, walked from opposite ends. Every peer was drawn as
  // inbound before, which was wrong for the 11 connections we opened ourselves.
  for (const o of vis) {
    if (!REDUCED) { o.t += dt * o.spd; if (o.t > 1) o.t -= 1; }
    const c = ctrl(o.sx, o.sy);
    const inbound = o.p.inbound;
    const t = inbound ? o.t : 1 - o.t;      // t always runs along the direction of travel
    const [px, py] = qpt([o.sx, o.sy], c, [cx, cy], t);
    octx.globalAlpha = o.fade * (1 - Math.pow(o.t, 3) * 0.5);
    octx.fillStyle = inbound ? '#DFFFF2' : '#8FF0CE';
    octx.shadowColor = 'rgba(10,193,142,1)'; octx.shadowBlur = 12;
    octx.beginPath(); octx.arc(px, py, 2.6, 0, 7); octx.fill();
    octx.shadowBlur = 0; octx.globalAlpha = 1;
  }

  // peer dots — radius by connection age, and a landing ring while joining
  for (const o of vis) {
    const rad = (2.2 + (o.p.age / maxAge) * 2.2) * (0.7 + o.fade * 0.3);
    if (o.alive && o.op < 0.98) {
      octx.globalAlpha = (1 - o.op) * 0.8;
      octx.strokeStyle = '#39E8B4'; octx.lineWidth = 1;
      octx.beginPath(); octx.arc(o.sx, o.sy, rad + (1 - o.op) * 13, 0, 7); octx.stroke();
    }
    octx.globalAlpha = o.fade;
    octx.fillStyle = o === hover ? '#FFFFFF' : '#39E8B4';
    octx.shadowColor = 'rgba(10,193,142,.95)'; octx.shadowBlur = 10;
    octx.beginPath(); octx.arc(o.sx, o.sy, rad, 0, 7); octx.fill();
    octx.shadowBlur = 0; octx.globalAlpha = 1;
  }

  // Tor ring — peers with no location, by design. Never plotted, never dropped.
  if (torCount > 0) {
    octx.save(); octx.translate(cx, cy); octx.rotate(REDUCED ? 0 : -rotY * 1.7);
    const rr = R * 0.135;
    octx.setLineDash([4, 6]); octx.strokeStyle = 'rgba(201,162,39,.5)'; octx.lineWidth = 1;
    octx.beginPath(); octx.arc(0, 0, rr, 0, 7); octx.stroke(); octx.setLineDash([]);
    for (let i = 0; i < torCount; i++) {
      const a = (i / Math.max(1, torCount)) * Math.PI * 2;
      octx.fillStyle = '#C9A227'; octx.shadowColor = 'rgba(201,162,39,.9)'; octx.shadowBlur = 7;
      octx.beginPath(); octx.arc(Math.cos(a) * rr, Math.sin(a) * rr, 2.4, 0, 7); octx.fill();
      octx.shadowBlur = 0;
    }
    octx.restore();
  }

  // node core — your position is unknown and stays unknown: centre-front.
  const pulse = REDUCED ? 0.5 : (Math.sin(now / 620) * 0.5 + 0.5);
  octx.fillStyle = 'rgba(10,193,142,' + (0.10 + pulse * 0.16).toFixed(3) + ')';
  octx.beginPath(); octx.arc(cx, cy, 8 + pulse * 6, 0, 7); octx.fill();
  octx.fillStyle = '#FFFFFF'; octx.shadowColor = 'rgba(10,193,142,1)'; octx.shadowBlur = 16;
  octx.beginPath(); octx.arc(cx, cy, 3.4, 0, 7); octx.fill(); octx.shadowBlur = 0;

  requestAnimationFrame(frame);
}
requestAnimationFrame(frame);

// hover / tap
function pick(ev) {
  const fr = field.getBoundingClientRect();
  const mx = ev.clientX - fr.left, my = ev.clientY - fr.top;
  let best = null, bd = 15;
  for (const o of live) {
    if (o.fade <= 0 || o.p.lat == null) continue;
    const d = Math.hypot(o.sx - mx, o.sy - my);
    if (d < bd) { bd = d; best = o; }
  }
  hover = best;
  if (!best) { tipEl.classList.remove('on'); return; }
  const hr = hero.getBoundingClientRect();
  tipEl.classList.add('on');
  tipEl.style.left = (fr.left - hr.left + best.sx) + 'px';
  tipEl.style.top = (fr.top - hr.top + best.sy) + 'px';
  document.getElementById('tipAddr').textContent = best.p.addr;
  document.getElementById('tipMeta').textContent =
    COUNTRY[best.p.country] + ' · ' + (best.p.inbound ? 'in' : 'out') + ' · ' + best.p.ping + 'ms';
}
hero.addEventListener('pointermove', pick);
hero.addEventListener('pointerdown', pick);
hero.addEventListener('pointerleave', () => { hover = null; tipEl.classList.remove('on'); });

// ---- connections — repainted on every join/leave ----------------------------
const DONUT_C = 2 * Math.PI * 64, GAP = 4;   // `C` is index.html's legacy beacon arc
const segClear = document.getElementById('segClear');
const segTor = document.getElementById('segTor');
const legendEl = document.getElementById('legend');
const truthEl = document.getElementById('truth');
const totalEl = document.getElementById('peerTotal');

function seg(el, count, offset) {
  const len = Math.max(0, (count / Math.max(1, total)) * DONUT_C - (count ? GAP : 0));
  el.style.strokeDasharray = len + ' ' + (DONUT_C - len);
  el.style.strokeDashoffset = -((offset / Math.max(1, total)) * DONUT_C);
}
// Onion peers first, lowest latency at the top — they are the scarce ones
// (23 known .onion of 33,048 addresses), so they get the top of the list
// rather than being buried under a dozen clearnet peers. Ping ascending
// within each group; a peer with no ping yet sorts last, not as 0.
function peerOrder(a, b) {
  const ta = a.p.tor ? 0 : 1, tb = b.p.tor ? 0 : 1;
  if (ta !== tb) return ta - tb;
  const pa = a.p.ping == null ? Infinity : a.p.ping;
  const pb = b.p.ping == null ? Infinity : b.p.ping;
  return pa - pb;
}

function fmtAge(s) {
  if (s < 3600) return Math.round(s / 60) + 'm';
  if (s < 86400) return (s / 3600).toFixed(1) + 'h';
  return (s / 86400).toFixed(1) + 'd';
}

// Real dashboard: POST /api/peers/disconnect -> RPC disconnectnode <addr>.
// One shot, not a ban — bitcoind may dial the address again on its own.
function disconnect(o, btn) {
  btn.disabled = true; btn.textContent = 'dropping';
  o.alive = false;                       // fades off the globe; donut follows
  setTimeout(() => { recount(); }, 240);
}

function renderPeers() {
  const on = live.filter(o => o.alive).sort(peerOrder);
  const inb = on.filter(o => o.p.inbound).length;
  const torN = on.filter(o => o.p.tor).length;
  const known = 23;                      // getnodeaddresses 0, .onion count
  document.getElementById('peersSummary').textContent =
    on.length + ' connected · ' + inb + ' inbound · ' + torN + ' via Tor · ' + known + ' onion known';
  document.getElementById('onionHint').textContent = torN === 0
    ? 'Bitcoin Cash has very few onion nodes (' + known + ' known here), so 0 connected is normal — not a fault.'
    : torN + ' onion peer' + (torN === 1 ? '' : 's') + ' connected of ' + known + ' known.';

  const t = document.getElementById('peersTable');
  t.textContent = '';
  for (const o of on) {
    const row = document.createElement('div');
    row.className = 'prow' + (o.p.inbound ? ' in' : '') + (o.p.tor ? ' tor' : '');
    row.innerHTML =
      '<span class="io">' + (o.p.inbound ? 'IN' : 'OUT') + '</span>' +
      '<span class="a"></span>' +
      '<span class="ms">' + (o.p.ping != null ? o.p.ping + 'ms' : '') + '</span>' +
      '<span class="ag">' + (o.p.age != null ? fmtAge(o.p.age) : '') + '</span>';
    // Peer-controlled string -> textContent, never innerHTML.
    row.querySelector('.a').textContent = (o.p.tor ? '[tor] ' : '') + o.p.addr;
    const btn = document.createElement('button');
    btn.className = 'dc'; btn.textContent = 'Disconnect';
    btn.setAttribute('aria-label', 'Disconnect peer ' + o.p.addr);
    btn.addEventListener('click', () => disconnect(o, btn));
    row.appendChild(btn);
    t.appendChild(row);
  }
}

function paint() {
  totalEl.textContent = total;
  renderPeers();
  requestAnimationFrame(() => {
    seg(segClear, clearCount, 0);
    seg(segTor, torCount, clearCount);
  });
  legendEl.innerHTML =
    '<div class="row"><span class="sw" style="background:#0AC18E"></span><span class="nm">Clearnet</span><span class="ct">' + clearCount + '</span></div>' +
    '<div class="row"><span class="sw" style="background:#C9A227"></span><span class="nm">Tor</span><span class="ct">' + torCount + '</span></div>';
  truthEl.innerHTML = torCount === 0
    ? '<b>No peers via Tor.</b> BCH\u2019s onion network is small — about 0.07% of known addresses are .onion — so zero is normal, not a fault.'
    : torCount + ' Tor peer' + (torCount > 1 ? 's' : '') + ' orbit the node marker: onion addresses have no location, by design.' +
      (unplaced ? ' ' + unplaced + ' peer isn\u2019t in the country table and is left unplaced.' : '');
}

// Sync ring — the beacon this card replaced, now riding on the globe. It is
// present only while there is something to report: once the node is out of
// IBD and verificationprogress rounds to 100%, it fades out for good.
const RING_C = 2 * Math.PI * 66;
let syncGone = false;
function setSync(progress, ibd) {
  if (syncGone) return;
  const pct = Math.min(100, progress * 100);
  document.getElementById('syncArc').style.strokeDashoffset = RING_C * (1 - pct / 100);
  document.getElementById('syncPct').innerHTML = pct.toFixed(pct >= 99.95 ? 0 : 1) + '<small>%</small>';
  if (!ibd && progress >= 0.9999) {
    syncGone = true;
    const w = document.getElementById('syncwrap');
    w.classList.add('done');
    setTimeout(() => w.remove(), 900);
  }
}

// ---- blocks rail
function faceCanvas(b, ours) {
  const c = document.createElement('canvas');
  const w = 154, h = 154;
  c.width = w * 2; c.height = h * 2;
  const g = c.getContext('2d'); g.scale(2, 2);
  let s = (b.height * 2654435761) >>> 0;
  const rnd = () => (s = (s * 1664525 + 1013904223) >>> 0) / 4294967296;

  g.fillStyle = ours ? '#1b1508' : '#0b1f18'; g.fillRect(0, 0, w, h);
  const n = Math.max(3, Math.min(11, Math.round(b.txs / 70)));
  for (let i = 0; i < n; i++) {
    const x = 12 + rnd() * (w - 24), y = 8 + rnd() * (h - 46), r = 16 + rnd() * 30;
    const gr = g.createRadialGradient(x, y, 0, x, y, r);
    gr.addColorStop(0, ours ? 'rgba(201,162,39,.62)' : 'rgba(10,193,142,.58)');
    gr.addColorStop(1, 'transparent');
    g.fillStyle = gr; g.beginPath(); g.arc(x, y, r, 0, 7); g.fill();
  }
  // fine scanline weave, echoing the globe's baked texture
  g.globalAlpha = .16; g.fillStyle = '#000';
  for (let y = 0; y < h; y += 3) g.fillRect(0, y, w, 1);
  g.globalAlpha = 1;
  // bottom shade so the label stays readable
  const sh = g.createLinearGradient(0, h - 56, 0, h);
  sh.addColorStop(0, 'transparent'); sh.addColorStop(1, 'rgba(0,0,0,.72)');
  g.fillStyle = sh; g.fillRect(0, h - 56, w, 56);
  return c;
}

const rail = document.getElementById('rail');
function renderBlocks(list) {
  rail.textContent = '';
  for (const b of (list || []).slice(0, 5)) {
    const ours = /LoneStrike Cash/.test(b.tag || '');
    const el = document.createElement('div');
    el.className = 'blk' + (ours ? ' ours' : '');
    const mins = Math.max(0, Math.round((Date.now() / 1000 - b.time) / 60));
    const mb = (b.size / 1e6).toFixed(1);
    el.innerHTML =
      '<div class="face"></div>' +
      '<div class="pool' + (b.tag && b.tag !== 'Unknown' ? '' : ' none') + '"></div>' +
      '<div class="lab"><div class="h">' + b.height.toLocaleString() + '</div>' +
      '<div class="s">' + mb + ' MB \u00b7 ' + (mins < 60 ? mins + 'm' : (mins / 60).toFixed(1) + 'h') + ' ago</div></div>';
    // tag comes from the coinbase — peer-controlled bytes. textContent only.
    el.querySelector('.pool').textContent = (b.tag && b.tag !== 'Unknown') ? b.tag : 'Unknown';
    el.querySelector('.face').appendChild(faceCanvas(b, ours));
    rail.appendChild(el);
  }
}
